parameters.jsCode:
const payload = $input.first().json.body.payload;
const paymentLink = payload.payment_link?.entity || {};
const payment = payload.payment?.entity || {};

return [{
  json: {
    deal_id: paymentLink.notes?.deal_id || '',
    client_name: paymentLink.customer?.name || payment.notes?.client_name || '',
    client_email: paymentLink.customer?.email || payment.email || '',
    amount: (payment.amount || paymentLink.amount || 0) / 100,
    currency: payment.currency || 'INR',
    payment_id: payment.id || '',
    payment_link_id: paymentLink.id || '',
    paid_at: new Date().toISOString()
  }
}];

